def validate(args, output):
    s = args[0]
    if output == '':
        digits = [c for c in s if c.isdigit()]
        letters = [c for c in s if c.isalpha()]
        return abs(len(digits) - len(letters)) > 1
    if len(output) != len(s):
        return False
    if sorted(output) != sorted(s):
        return False
    for i in range(len(output) - 1):
        if output[i].isdigit() == output[i+1].isdigit():
            return False
    return True

