    const s = args[0];
    if (output === '') {
        const digits = s.split('').filter(c => c >= '0' && c <= '9');
        const letters = s.split('').filter(c => c >= 'a' && c <= 'z');
        return Math.abs(digits.length - letters.length) > 1;
    }
    if (output.length !== s.length) return false;
    if (output.split('').sort().join('') !== s.split('').sort().join('')) return false;
    for (let i = 0; i < output.length - 1; i++) {
        const isDigit1 = output[i] >= '0' && output[i] <= '9';
        const isDigit2 = output[i+1] >= '0' && output[i+1] <= '9';
        if (isDigit1 === isDigit2) return false;
    }
    return true;
}

