def gen(rng, size):
    n = rng.randint(1, min(size, 500))
    chars = []
    for _ in range(n):
        if rng.random() < 0.5:
            chars.append(str(rng.randint(0, 9)))
        else:
            chars.append(chr(rng.randint(ord('a'), ord('z'))))
    rng.shuffle(chars)
    return [''.join(chars)]

