    const letters = s.split('').filter(c => c >= 'a' && c <= 'z');
    if (Math.abs(digits.length - letters.length) > 1) return '';
    let big = digits.length >= letters.length ? digits : letters;
    let small = digits.length >= letters.length ? letters : digits;
    let result = '';
